import sys

def solve() -> None:
    data = list(map(int, sys.stdin.read().split()))
    if not data:
        return
    N, M = data[0], data[1]
    A = data[2:]

    total = sum(A)
    if total <= M:
        print("infinite")
        return

    low = 0
    high = max(A)          # infeasible, because total > M

    # helper to compute f(x)
    def subsidy(x: int) -> int:
        s = 0
        for v in A:
            s += v if v < x else x
        return s

    while low < high:
        mid = (low + high + 1) // 2
        if subsidy(mid) <= M:
            low = mid
        else:
            high = mid - 1

    print(low)


