    solve()

class Solution:
    def getEncryptedString(self, s: str, k: int) -> str:
        n = len(s)
        # Effective shift after removing full cycles
        k %= n
        # Build the encrypted string by rotating left by k positions
        encrypted_chars = [s[(i + k) % n] for i in range(n)]
