class Solution:
    def numberOfSubmatrices(self, grid: List[List[str]]) -> int:
        if not grid or not grid[0]:
            return 0
        m, n = len(grid), len(grid[0])

        # prefix sums, one extra row and column of zeros for easier formulas
        Xpref = [[0] * (n + 1) for _ in range(m + 1)]
        Ypref = [[0] * (n + 1) for _ in range(m + 1)]

        for i in range(m):
            for j in range(n):
                isX = 1 if grid[i][j] == 'X' else 0
                isY = 1 if grid[i][j] == 'Y' else 0
                Xpref[i + 1][j + 1] = (Xpref[i][j + 1] + Xpref[i + 1][j]
                                      - Xpref[i][j] + isX)
                Ypref[i + 1][j + 1] = (Ypref[i][j + 1] + Ypref[i + 1][j]
                                      - Ypref[i][j] + isY)

        ans = 0
        for i in range(m):
            for j in range(n):
                x_cnt = Xpref[i + 1][j + 1]
                y_cnt = Ypref[i + 1][j + 1]
                if x_cnt == y_cnt and x_cnt > 0:
                    ans += 1
        return ans

