INF = 10 ** 18


class Node:
    __slots__ = ("next", "fail", "output")
    def __init__(self):
        self.next = {}          # char -> Node
        self.fail = None        # failure link
        self.output = []        # list of (length, cost)


class Solution:
    def minimumCost(self, target: str, words: List[str], costs: List[int]) -> int:
        # 1. keep cheapest cost for each distinct word
        best = {}
        for w, c in zip(words, costs):
            if w not in best or c < best[w]:
                best[w] = c

        # 2. build trie
        root = Node()
        for w, c in best.items():
            node = root
            for ch in w:
                if ch not in node.next:
                    node.next[ch] = Node()
                node = node.next[ch]
            node.output.append((len(w), c))

        # 3. build failure links (BFS)
        q = collections.deque()
        # first level: fail -> root
        for child in root.next.values():
            child.fail = root
            q.append(child)

        while q:
            cur = q.popleft()
            # inherit outputs from fail node
            if cur.fail:
                cur.output.extend(cur.fail.output)

            for ch, nxt in cur.next.items():
                # compute failure link for nxt
                f = cur.fail
                while f and ch not in f.next:
                    f = f.fail
                nxt.fail = f.next[ch] if f and ch in f.next else root
                q.append(nxt)

        # 4. DP over the target while scanning it with the automaton
        n = len(target)
        dp = [INF] * (n + 1)
        dp[0] = 0

        node = root
        for i, ch in enumerate(target):
            # follow transitions, using failure links on mismatch
            while node and ch not in node.next:
                node = node.fail
            node = node.next[ch] if node and ch in node.next else root

            # all words that end at position i
            for length, cost in node.output:
                start = i - length + 1
                if dp[start] + cost < dp[i + 1]:
                    dp[i + 1] = dp[start] + cost

        return dp[n] if dp[n] < INF else -1

class Solution:
    def getSmallestString(self, s: str) -> str:
        # convert to list for easy swapping
        chars = list(s)
        n = len(chars)

        for i in range(n - 1):
            # same parity ?
            if (int(chars[i]) % 2) == (int(chars[i + 1]) % 2):
                # would the swap make the string smaller ?
                if chars[i + 1] < chars[i]:
                    # perform the single allowed swap and stop
                    chars[i], chars[i + 1] = chars[i + 1], chars[i]
                    break

        return ''.join(chars)

class Solution:
    def minChanges(self, n: int, k: int) -> int:
        # If k has a 1 where n has a 0, impossible
        if k & ~n:
            return -1
        # Number of bits that differ (1 in n, 0 in k)
        return (n ^ k).bit_count()

