class Solution:
    def numberOfSubstrings(self, s: str) -> int:
        n = len(s)
        # maximal possible number of zeros in a dominant substring
        B = int(n ** 0.5) + 1

        ans = 0
        for i in range(n):
            zeros = 0
            ones = 0
            # extend the right border while zeros stay ≤ B
            for j in range(i, n):
                if s[j] == '0':
                    zeros += 1
                    if zeros > B:          # cannot become dominant any more
                        break
                else:
                    ones += 1

                if ones >= zeros * zeros:  # condition (1)
                    ans += 1
        return ans

