import math

class UnionFind:
    def __init__(self, n: int):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x: int) -> int:
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]
            x = self.parent[x]
        return x

    def union(self, a: int, b: int) -> None:
        ra, rb = self.find(a), self.find(b)
        if ra == rb:
            return
        if self.rank[ra] < self.rank[rb]:
            self.parent[ra] = rb
        elif self.rank[ra] > self.rank[rb]:
            self.parent[rb] = ra
        else:
            self.parent[rb] = ra
            self.rank[ra] += 1


class Solution:
    def canReachCorner(self, xCorner: int, yCorner: int,
                       circles: List[List[int]]) -> bool:
        n = len(circles)
        # indices for the four sides
        LEFT, RIGHT, BOTTOM, TOP = n, n + 1, n + 2, n + 3
        uf = UnionFind(n + 4)

        # ----- circle – circle connections -----
        for i in range(n):
            xi, yi, ri = circles[i]
            for j in range(i + 1, n):
                xj, yj, rj = circles[j]
                dx = xi - xj
                dy = yi - yj
                # compare squared distances to avoid sqrt
                if dx * dx + dy * dy <= (ri + rj) * (ri + rj):
                    uf.union(i, j)

        # ----- circle – side connections -----
        for i, (x, y, r) in enumerate(circles):
            # left side  x = 0, 0 <= y <= yCorner
            if x - r <= 0 and y + r >= 0 and y - r <= yCorner:
                uf.union(i, LEFT)

            # right side x = xCorner
            if x + r >= xCorner and y + r >= 0 and y - r <= yCorner:
                uf.union(i, RIGHT)

            # bottom side y = 0
            if y - r <= 0 and x + r >= 0 and x - r <= xCorner:
                uf.union(i, BOTTOM)

            # top side y = yCorner
            if y + r >= yCorner and x + r >= 0 and x - r <= xCorner:
                uf.union(i, TOP)

        # ----- check forbidden connections -----
        if (uf.find(LEFT) == uf.find(RIGHT) or
            uf.find(BOTTOM) == uf.find(TOP) or
            uf.find(LEFT) == uf.find(BOTTOM) or
            uf.find(RIGHT) == uf.find(TOP)):
            return False
        return True

