class Solution:
    def finalPositionOfSnake(self, n: int, commands: List[str]) -> int:
        """
        Returns the linear index of the cell where the snake ends after executing
        the given sequence of movement commands on an n x n grid.
        """
        # start at top‑left corner (0,0)
        row, col = 0, 0

        # process each command
        for cmd in commands:
            if cmd == "UP":
                row -= 1
            elif cmd == "DOWN":
                row += 1
            elif cmd == "LEFT":
                col -= 1
            elif cmd == "RIGHT":
                col += 1
            # No need for bounds checking – the problem guarantees validity

        # convert final (row, col) to linear index
        return row * n + col

