from collections import defaultdict, Counter

class Solution:
    def winningPlayerCount(self, n: int, pick: List[List[int]]) -> int:
        # cnt[player] -> Counter of colours
        cnt = defaultdict(Counter)

        # step 2: count picks
        for player, colour in pick:
            cnt[player][colour] += 1

        # step 3: evaluate each player
        winners = 0
        for i in range(n):
            needed = i + 1          # minimum balls of same colour to win
            # if player i never picked anything, cnt[i] is empty -> loop skips
            for colour_cnt in cnt[i].values():
                if colour_cnt >= needed:
                    winners += 1
                    break   # no need to check other colours for this player
        return winners

