class Solution:
    def minFlips(self, grid: List[List[int]]) -> int:
        m = len(grid)
        n = len(grid[0])

        # flips to make all rows palindromic
        row_flips = 0
        half_n = n // 2
        for r in range(m):
            row = grid[r]
            for j in range(half_n):
                if row[j] != row[n - 1 - j]:
                    row_flips += 1

        # flips to make all columns palindromic
        col_flips = 0
        half_m = m // 2
        for c in range(n):
            for i in range(half_m):
                if grid[i][c] != grid[m - 1 - i][c]:
                    col_flips += 1

        return min(row_flips, col_flips)

