import sys

INF = 10 ** 20          # larger than any possible value (answer ≤ 1e18)

def ceil_div(a, b):
    """ceil(a / b)  with b > 0, works for negative a as well"""
    return -((-a) // b)

def make_leaf(A, B):
    """return piece list of one position (0‑based lower bound)"""
    if B == 1:
        # multiplication never wins
        return [(0, 1, A)]
    # threshold where multiplication becomes at least as good as addition
    T = ceil_div(A, B - 1)          # = ceil(A/(B-1))
    # piece for addition, then multiplication
    return [(0, 1, A), (T, B, 0)]

def compose(L, R):
    """return R ∘ L  (first L, then R)"""
    res = []
    # iterate over pieces of L
    for i in range(len(L)):
        lL = L[i][0]
        a1, b1 = L[i][1], L[i][2]
        rL = L[i + 1][0] - 1 if i + 1 < len(L) else INF

        # iterate over pieces of R
        for j in range(len(R)):
            lR = R[j][0]
            a2, b2 = R[j][1], R[j][2]
            rR = R[j + 1][0] - 1 if j + 1 < len(R) else INF

            # v such that a1*v + b1 lies in [lR, rR]
            low = max(lL, ceil_div(lR - b1, a1))
            high = min(rL, (rR - b1) // a1)
            if low <= high:
                a_new = a2 * a1
                b_new = a2 * b1 + b2
                if res and res[-1][1] == a_new and res[-1][2] == b_new:
                    # same linear expression – interval just extends
                    continue
                res.append((low, a_new, b_new))
    return res

class SegTree:
    def __init__(self, A, B):
        n = len(A)
        size = 1
        while size < n:
            size <<= 1
        self.N = size
        self.data = [None] * (2 * size)
        # leaves
        for i in range(n):
            self.data[size + i] = make_leaf(A[i], B[i])
        for i in range(n, size):
            # dummy identity function (v -> v)
            self.data[size + i] = [(0, 1, 0)]
        # build
        for i in range(size - 1, 0, -1):
            self.data[i] = compose(self.data[i << 1], self.data[i << 1 | 1])

    def _update(self, idx, A, B):
        pos = self.N + idx
        self.data[pos] = make_leaf(A, B)
        pos >>= 1
        while pos:
            self.data[pos] = compose(self.data[pos << 1], self.data[pos << 1 | 1])
            pos >>= 1

    def point_update_A(self, idx, x, B_arr):
        # B_arr is the current B array, needed only for leaf creation
        self._update(idx, x, B_arr[idx])

    def point_update_B(self, idx, x, A_arr):
        self._update(idx, A_arr[idx], x)

    def _query(self, l, r, node, nl, nr):
        if l <= nl and nr <= r:
            return self.data[node]
        mid = (nl + nr) >> 1
        if r <= mid:
            return self._query(l, r, node << 1, nl, mid)
        if l > mid:
            return self._query(l, r, node << 1 | 1, mid + 1, nr)
        left = self._query(l, r, node << 1, nl, mid)
        right = self._query(l, r, node << 1 | 1, mid + 1, nr)
        return compose(left, right)

    def range_query(self, l, r):
        """0‑based inclusive, returns function list"""
        return self._query(l, r, 1, 0, self.N - 1)

def solve() -> None:
    it = iter(sys.stdin.read().strip().split())
    N = int(next(it))
    A = [int(next(it)) for _ in range(N)]
    B = [int(next(it)) for _ in range(N)]
    seg = SegTree(A, B)

    Q = int(next(it))
    out_lines = []
    for _ in range(Q):
        typ = int(next(it))
        if typ == 1:
            i = int(next(it)) - 1
            x = int(next(it))
            A[i] = x
            seg.point_update_A(i, x, B)
        elif typ == 2:
            i = int(next(it)) - 1
            x = int(next(it))
            B[i] = x
            seg.point_update_B(i, x, A)
        else:   # typ == 3
            l = int(next(it)) - 1
            r = int(next(it)) - 1
            func = seg.range_query(l, r)
            # first piece always starts at 0, answer = b of that piece
            ans = func[0][2]
            out_lines.append(str(ans))
    sys.stdout.write("\n".join(out_lines))

