import sys

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    notes = [(int(next(it)), next(it)) for _ in range(N)]

    INF = 10 ** 9
    K = 100  # number of keys, keys are 1..100

    # dp[l][r] : minimal fatigue after processed notes, left on l, right on r
    dp = [[0] * (K + 1) for _ in range(K + 1)]   # initially all 0

    for a, hand in notes:
        nxt = [[INF] * (K + 1) for _ in range(K + 1)]
        if hand == 'L':
            for l in range(1, K + 1):
                row = dp[l]
                for r in range(1, K + 1):
                    cur = row[r]
                    if cur == INF:
                        continue
                    cost = cur + abs(a - l)
                    if cost < nxt[a][r]:
                        nxt[a][r] = cost
        else:  # hand == 'R'
            for l in range(1, K + 1):
                row = dp[l]
                for r in range(1, K + 1):
                    cur = row[r]
                    if cur == INF:
                        continue
                    cost = cur + abs(a - r)
                    if cost < nxt[l][a]:
                        nxt[l][a] = cost
        dp = nxt

    ans = INF
    for l in range(1, K + 1):
        for r in range(1, K + 1):
            if dp[l][r] < ans:
                ans = dp[l][r]
    print(ans)


