        C[i] = int(next(it))
        D[i] = int(next(it))

    # orientation >0  : point is left of directed line (i -> j)
    def cross(i, j, x, y):
        return (C[j] - A[i]) * (y - B[i]) - (D[j] - B[i]) * (x - A[i])

    # result, 0‑based indices
    R = [-1] * N

    def recurse(red_idxs, blue_idxs):
        if not red_idxs:
            return
        # try all pairs
        for i in red_idxs:
            for j in blue_idxs:
                cntR = cntB = 0
                # count reds left of Pi->Qj
                for p in red_idxs:
                    if p == i:
                        continue
                    if cross(i, j, A[p], B[p]) > 0:
                        cntR += 1
                # count blues left of Pi->Qj
                for q in blue_idxs:
                    if q == j:
                        continue
                    if cross(i, j, C[q], D[q]) > 0:
                        cntB += 1
                if cntR == cntB:
                    # found a balanced pair
                    R[i] = j
                    leftR = []
                    leftB = []
                    rightR = []
                    rightB = []
                    for p in red_idxs:
                        if p == i:
                            continue
                        if cross(i, j, A[p], B[p]) > 0:
                            leftR.append(p)
                        else:
                            rightR.append(p)
                    for q in blue_idxs:
                        if q == j:
                            continue
                        if cross(i, j, C[q], D[q]) > 0:
                            leftB.append(q)
                        else:
                            rightB.append(q)
                    recurse(leftR, leftB)
                    recurse(rightR, rightB)
                    return
        # According to the geometric theorem this line is never reached.
        # If it were, we would output -1.
        print(-1)
        sys.exit(0)

    recurse(list(range(N)), list(range(N)))
    # output 1‑based permutation
    out = ' '.join(str(R[i] + 1) for i in range(N))
    print(out)


