class Solution:
    def largestPalindrome(self, n: int, k: int) -> str:
        # ---------- 1. powers of 10 modulo k ----------
        pow10 = [1] * (n + 1)          # pow10[e] = 10^e % k
        for i in range(1, n + 1):
            pow10[i] = (pow10[i - 1] * 10) % k

        # ---------- 2. weight of each position in the left half ----------
        m = (n + 1) // 2                # length of the left half
        weight = [0] * m
        for i in range(m):
            if n % 2 == 1 and i == n // 2:          # middle of odd length
                weight[i] = pow10[n - 1 - i] % k
            else:
                w = (pow10[n - 1 - i] + pow10[i]) % k
                weight[i] = w

        # ---------- 3. suffix DP, stored as bit masks ----------
        # bit r is set  <=>  remainder r is reachable
        suffix = [0] * (m + 1)
        suffix[m] = 1 << 0                     # only remainder 0

        for i in range(m - 1, -1, -1):
            mask = 0
            w = weight[i]
            for r in range(k):
                if (suffix[i + 1] >> r) & 1:
                    for d in range(10):
                        if i == 0 and d == 0:
                            continue          # no leading zero
                        new_r = (d * w + r) % k
                        mask |= 1 << new_r
            suffix[i] = mask

        # there is always at least one solution, but keep the check
        if not (suffix[0] & 1):                # remainder 0 not reachable
            return ""

        # ---------- 4. greedy reconstruction ----------
        need = 0
        left_digits = []
        for i in range(m):
            w = weight[i]
            for d in range(9, -1, -1):
                if i == 0 and d == 0:
                    continue
                r_needed = (need - d * w) % k
                if (suffix[i + 1] >> r_needed) & 1:
                    left_digits.append(str(d))
                    need = r_needed
                    break

        # ---------- 5. build the full palindrome ----------
        left = ''.join(left_digits)
        if n % 2 == 0:
            right = left[::-1]
        else:
            right = left[:-1][::-1]   # drop the middle digit once
        return left + right

