class Solution:
    def countPairs(self, nums: List[int]) -> int:
        # ---------- helper: all values reachable from one number ----------
        def reachable(val: int) -> set[int]:
            s = str(val)
            n = len(s)
            res = {val}                     # zero swaps
            # all possible swaps of two positions
            for i in range(n):
                for j in range(i + 1, n):
                    lst = list(s)
                    lst[i], lst[j] = lst[j], lst[i]
                    swapped = int(''.join(lst))   # leading zeros are ignored
                    res.add(swapped)
            return res

        # pre‑compute reachable sets for every array element
        reach = [reachable(v) for v in nums]

        ans = 0
        n = len(nums)
        for i in range(n - 1):
            for j in range(i + 1, n):
                if nums[j] in reach[i] or nums[i] in reach[j]:
                    ans += 1
        return ans

class Solution:
    def checkTwoChessboards(self, coordinate1: str, coordinate2: str) -> bool:
        # helper to compute parity of (column + row)
        def parity(coord: str) -> int:
            col = ord(coord[0]) - ord('a') + 1   # 'a' -> 1, ..., 'h' -> 8
            row = int(coord[1])                  # '1'..'8' -> 1..8
            return (col + row) & 1               # same as % 2

        return parity(coordinate1) == parity(coordinate2)

