class Solution:
    def resultsArray(self, queries: List[List[int]], k: int) -> List[int]:
        # max-heap for the k smallest distances (store negative values)
        small = []          # type: List[int]
        # min-heap for the remaining distances
        large = []          # type: List[int]

        ans = []

        for x, y in queries:
            d = abs(x) + abs(y)

            if len(small) < k:
                # we still need elements to fill the k‑th position
                heapq.heappush(small, -d)
            else:
                # small already holds k elements
                if d < -small[0]:
                    # d belongs to the k smallest
                    heapq.heappush(small, -d)
                    # move the largest of small to large
                    moved = -heapq.heappop(small)
                    heapq.heappush(large, moved)
                else:
                    heapq.heappush(large, d)

            # If total obstacles < k, move from large to small as much as possible
            while len(small) < k and large:
                heapq.heappush(small, -heapq.heappop(large))

            # produce answer for this query
            if len(small) == k:
                ans.append(-small[0])
            else:
                ans.append(-1)

        return ans

