class Solution:
    def maxScore(self, grid: List[List[int]]) -> int:
        R = len(grid)
        # 1. build mask for each value
        value_mask = {}                     # value -> bitmask of rows containing it
        for r, row in enumerate(grid):
            for v in row:
                if v not in value_mask:
                    value_mask[v] = 0
                value_mask[v] |= (1 << r)

        # 2. DP over subsets of rows
        INF_NEG = -10**9
        dp = [INF_NEG] * (1 << R)
        dp[0] = 0

        # iterate over all distinct values (order does not matter)
        for v, rows_mask in value_mask.items():
            # iterate masks in decreasing order to avoid using v twice
            for mask in range((1 << R) - 1, -1, -1):
                cur = dp[mask]
                if cur == INF_NEG:
                    continue
                # rows that have value v and are still free
                free = rows_mask & (~mask)
                # try to assign v to each such row
                while free:
                    # isolate lowest set bit
                    i = free & -free
                    row = (i.bit_length() - 1)   # index of the row
                    new_mask = mask | i
                    if dp[new_mask] < cur + v:
                        dp[new_mask] = cur + v
                    # remove this bit and continue
                    free ^= i

        # 3. answer = best over all masks
        return max(dp)

