class Solution:
    def maxPossibleScore(self, start: List[int], d: int) -> int:
        # build intervals and sort by left border
        intervals = [(s, s + d) for s in start]
        intervals.sort(key=lambda x: x[0])

        # helper: can we place points with minimal distance >= dist ?
        def feasible(dist: int) -> bool:
            # place first point at the leftmost possible position
            prev = None
            for L, R in intervals:
                if prev is None:
                    cur = L
                else:
                    cur = max(L, prev + dist)
                if cur > R:          # outside the interval -> impossible
                    return False
                prev = cur
            return True

        # binary search on answer
        lo = 0
        hi = intervals[-1][1] - intervals[0][0] + 1   # exclusive upper bound
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                lo = mid + 1
            else:
                hi = mid
        return lo - 1

