INF_NEG = -10**30          # sufficiently small for max queries


class Line:
    __slots__ = ("m", "b")
    def __init__(self, m: int = 0, b: int = INF_NEG):
        self.m = m          # slope
        self.b = b          # intercept

    def value(self, x: int) -> int:
        return self.m * x + self.b


class Node:
    __slots__ = ("l", "r", "line", "left", "right")
    def __init__(self, l: int, r: int):
        self.l = l
        self.r = r
        self.line = Line()          # initially a line that returns -inf
        self.left: Optional["Node"] = None
        self.right: Optional["Node"] = None


class LiChaoTree:
    """Maximum Li Chao segment tree on integer domain [x_left, x_right]"""
    def __init__(self, x_left: int, x_right: int):
        self.root = Node(x_left, x_right)

    def _add_line(self, node: Node, new: Line):
        l, r = node.l, node.r
        mid = (l + r) // 2

        left_is_better = new.value(l) > node.line.value(l)
        mid_is_better = new.value(mid) > node.line.value(mid)

        if mid_is_better:
            node.line, new = new, node.line   # keep the better one at mid

        if l == r:
            return

        if left_is_better != mid_is_better:
            # the worse line may be better on the left half
            if node.left is None:
                node.left = Node(l, mid)
            self._add_line(node.left, new)
        else:
            # the worse line may be better on the right half
            if node.right is None:
                node.right = Node(mid + 1, r)
            self._add_line(node.right, new)

    def add_line(self, m: int, b: int):
        self._add_line(self.root, Line(m, b))

    def _query(self, node: Optional[Node], x: int) -> int:
        if node is None:
            return INF_NEG
        res = node.line.value(x)
        if node.l == node.r:
            return res
        mid = (node.l + node.r) // 2
        if x <= mid:
            return max(res, self._query(node.left, x))
        else:
            return max(res, self._query(node.right, x))

    def query(self, x: int) -> int:
        return self._query(self.root, x)


class Solution:
    def findMaximumScore(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 1:
            return 0

        # DP array (optional, we only need the last value, but keep for clarity)
        dp = [0] * n

        # Li Chao tree on domain [0, n-1]
        tree = LiChaoTree(0, n - 1)

        # line for i = 0 : slope = nums[0], intercept = dp[0] - 0*nums[0] = 0
        tree.add_line(nums[0], 0)

        for j in range(1, n):
            # best previous line evaluated at x = j
            dp[j] = tree.query(j)

            # insert line for this j for future positions
            slope = nums[j]
            intercept = dp[j] - j * nums[j]
            tree.add_line(slope, intercept)

        return dp[-1]

