class Solution:
    def maxScore(self, a: List[int], b: List[int]) -> int:
        # dp[t] = best score after picking first t elements of a
        INF_NEG = -10**30          # sufficiently small
        dp = [0] + [INF_NEG] * 4   # dp[0]=0, others = -inf

        for x in b:
            # update backwards so each b element is used at most once
            for t in range(4, 0, -1):
                cand = dp[t-1] + a[t-1] * x
                if cand > dp[t]:
                    dp[t] = cand

        return dp[4]

