class Solution:
    def minValidStrings(self, words: List[str], target: str) -> int:
        # ---------- build trie ----------
        root = TrieNode()
        for w in words:
            node = root
            for ch in w:
                if ch not in node.children:
                    node.children[ch] = TrieNode()
                node = node.children[ch]
                # we do NOT need to mark ends; every node is a valid prefix

        n = len(target)
        INF = n + 1          # any value > possible answer
        dp = [INF] * (n + 1)
        dp[0] = 0

        # ---------- DP over target ----------
        for i in range(n):
            if dp[i] == INF:
                continue          # unreachable prefix
            node = root
            j = i
            while j < n:
                ch = target[j]
                if ch not in node.children:
                    break
                node = node.children[ch]
                # substring target[i:j+1] is a valid prefix
                if dp[j + 1] > dp[i] + 1:
                    dp[j + 1] = dp[i] + 1
                j += 1

        return dp[n] if dp[n] != INF else -1

