class Solution:
    def maximumValueSum(self, board: List[List[int]]) -> int:
        m, n = len(board), len(board[0])

        # ---------- 1. pre‑compute the two best values of each row for every excluded column ----------
        # keep the three largest entries of each row (value, column)
        top_three = []
        for r in range(m):
            row_vals = [(board[r][c], c) for c in range(n)]
            row_vals.sort(reverse=True)          # descending by value
            top_three.append(row_vals[:3])       # at most three entries

        # bestTwo[r][c] = list of up to two (value, column) pairs, columns != c
        bestTwo = [[[] for _ in range(n)] for _ in range(m)]
        for r in range(m):
            for excl_c in range(n):
                cand = []
                for val, col in top_three[r]:
                    if col != excl_c:
                        cand.append((val, col))
                        if len(cand) == 2:
                            break
                bestTwo[r][excl_c] = cand   # length 1 or 2 (never empty because n>=3)

        # ---------- 2. main enumeration ----------
        # rows without a given row
        rows_without = [[r for r in range(m) if r != excl] for excl in range(m)]

        INF_NEG = -10**18
        answer = INF_NEG

        for excl_row in range(m):
            rows_list = rows_without[excl_row]          # all rows except excl_row
            for excl_col in range(n):
                best_pair = INF_NEG

                # enumerate unordered pairs of rows from rows_list
                L = len(rows_list)
                for i in range(L):
                    r1 = rows_list[i]
                    cand1 = bestTwo[r1][excl_col]
                    for j in range(i + 1, L):
                        r2 = rows_list[j]
                        cand2 = bestTwo[r2][excl_col]

                        # try all combinations (max 4)
                        for v1, c1 in cand1:
                            for v2, c2 in cand2:
                                if c1 != c2:          # columns must differ
                                    s = v1 + v2
                                    if s > best_pair:
                                        best_pair = s

                # total value when the third rook is placed at (excl_row, excl_col)
                total = board[excl_row][excl_col] + best_pair
                if total > answer:
                    answer = total

        return answer

