class Solution:
    def countGoodIntegers(self, n: int, k: int) -> int:
        # pre‑compute factorials up to 10
        fact = [1] * (n + 1)
        for i in range(1, n + 1):
            fact[i] = fact[i - 1] * i

        answer = 0

        # ------------------------------------------------------------------
        # enumerate all digit count vectors c0..c9 with sum = n
        def dfs(digit: int, left: int, cnt: List[int]):
            nonlocal answer
            if digit == 10:
                if left != 0:
                    return
                # ---------- 1. palindrome feasibility ----------
                odd_cnt = sum(c % 2 for c in cnt)
                if n % 2 == 0:
                    if odd_cnt != 0:
                        return
                else:
                    if odd_cnt != 1:
                        return

                # ---------- 2. try to build a divisible palindrome ----------
                half_len = n // 2
                half_digits = []
                for d in range(10):
                    half_digits.extend([d] * (cnt[d] // 2))

                # middle digit for odd length (the one with odd count)
                middle_digit = None
                if n % 2 == 1:
                    for d in range(10):
                        if cnt[d] % 2 == 1:
                            middle_digit = d
                            break

                # generate all distinct permutations of the half
                seen = set()
                good_pal_exists = False
                for perm in permutations(half_digits):
                    if perm in seen:
                        continue
                    seen.add(perm)

                    # leading zero check
                    if perm[0] == 0:
                        continue

                    # build palindrome as integer (mod k)
                    # we can compute the whole number because n ≤ 10
                    left_part = ''.join(str(d) for d in perm)
                    right_part = left_part[::-1]
                    if middle_digit is not None:
                        pal_str = left_part + str(middle_digit) + right_part
                    else:
                        pal_str = left_part + right_part

                    # leading zero already excluded, now test divisibility
                    if int(pal_str) % k == 0:
                        good_pal_exists = True
                        break

                if not good_pal_exists:
                    return

                # ---------- 3. count how many original numbers have this multiset ----------
                total = fact[n]
                for c in cnt:
                    total //= fact[c]

                if cnt[0] > 0:
                    bad = fact[n - 1]
                    bad //= fact[cnt[0] - 1]
                    for d in range(1, 10):
                        bad //= fact[cnt[d]]
                else:
                    bad = 0

                answer += total - bad
                return

            # try all possible counts for current digit
            for c in range(left + 1):
                cnt[digit] = c
                dfs(digit + 1, left - c, cnt)
            cnt[digit] = 0  # reset (not strictly necessary)

        dfs(0, n, [0] * 10)
        return answer

