class Solution:
    def maxValue(self, nums: List[int], k: int) -> int:
        n = len(nums)
        MAX_VAL = 128          # 0 .. 127

        # ---------- prefix DP ----------
        prefix_mask = [0] * n          # mask of OR-values with exactly k elements
        dp = [0] * (k + 1)
        dp[0] = 1 << 0                 # empty set → OR = 0

        for i, x in enumerate(nums):
            limit = min(i + 1, k)
            for t in range(limit, 0, -1):
                prev = dp[t - 1]
                if prev == 0:
                    continue
                new_mask = 0
                # iterate over all possible v (0..127)
                for v in range(MAX_VAL):
                    if (prev >> v) & 1:
                        new_mask |= 1 << (v | x)
                dp[t] |= new_mask
            prefix_mask[i] = dp[k]

        # ---------- suffix DP ----------
        suffix_mask = [0] * n
        dp = [0] * (k + 1)
        dp[0] = 1 << 0

        for idx in range(n - 1, -1, -1):
            x = nums[idx]
            limit = min(n - idx, k)
            for t in range(limit, 0, -1):
                prev = dp[t - 1]
                if prev == 0:
                    continue
                new_mask = 0
                for v in range(MAX_VAL):
                    if (prev >> v) & 1:
                        new_mask |= 1 << (v | x)
                dp[t] |= new_mask
            suffix_mask[idx] = dp[k]

        # ---------- combine ----------
        best = 0
        # split after position p (p is last index of first half)
        for p in range(k - 1, n - k):
            left = prefix_mask[p]
            right = suffix_mask[p + 1]
            if left == 0 or right == 0:
                continue
            # enumerate set bits
            for v1 in range(MAX_VAL):
                if (left >> v1) & 1:
                    for v2 in range(MAX_VAL):
                        if (right >> v2) & 1:
                            cur = v1 ^ v2
                            if cur > best:
                                best = cur
                                if best == 127:          # maximal possible
                                    return 127
        return best

class Solution:
    def countOfSubstrings(self, word: str, k: int) -> int:
        # bit masks for the five vowels
        vowel_to_bit = {'a': 1 << 0,
                        'e': 1 << 1,
                        'i': 1 << 2,
                        'o': 1 << 3,
                        'u': 1 << 4}
        full_mask = (1 << 5) - 1          # 0b11111 == 31

        n = len(word)
        ans = 0

        for i in range(n):
            mask = 0
            consonants = 0
            for j in range(i, n):
                ch = word[j]
                if ch in vowel_to_bit:
                    mask |= vowel_to_bit[ch]
                else:
                    consonants += 1

                if consonants > k:        # cannot become valid later
                    break

                if consonants == k and mask == full_mask:
                    ans += 1

        return ans

