def solve() -> None:
    it = iter(sys.stdin.read().strip().split())
    N = int(next(it))
    A = [int(next(it)) for _ in range(N)]
    B = [int(next(it)) for _ in range(N - 1)]

    A.sort()
    B.sort()

    # pref[i] : first i toys (i from 0..N-1) satisfy a_j <= b_j
    pref = [True] * (N)          # size N, pref[0]..pref[N-1]
    for i in range(1, N):
        pref[i] = pref[i - 1] and (A[i - 1] <= B[i - 1])

    # suff[i] : toys i..N satisfy a_j <= b_{j-1}
    # we store indices 0..N+1, but only need 2..N+1
    INF = 10 ** 18
    suff = [True] * (N + 2)      # suff[N+1] = True
    # compute for i = N .. 2
    for i in range(N, 1, -1):
        # need A[i-1] <= B[i-2]
        suff[i] = suff[i + 1] and (A[i - 1] <= B[i - 2])

    answer = INF

    for k in range(1, N + 1):          # insertion position (1‑based)
        if not pref[k - 1]:
            continue
        if not suff[k + 1]:
            continue

        low = A[k - 1]                 # ak
        if k > 1:
            low = max(low, B[k - 2])   # bk-1
        if k < N:
            high = B[k - 1]            # bk
        else:
            high = INF

        if low <= high:
            if low < answer:
                answer = low

    if answer == INF:
        print(-1)
    else:
        print(answer)


if __name__ == "__main__":
    solve()

