def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    M = int(next(it))

    INF = M + 1
    best = [INF] * (M + 2)          # 1‑based, extra cell for simplicity

    for _ in range(N):
        L = int(next(it))
        R = int(next(it))
        if R < best[L]:
            best[L] = R

    suffix = [INF] * (M + 2)        # suffix[M+1] stays INF
    for x in range(M, 0, -1):
        suffix[x] = best[x] if best[x] < suffix[x + 1] else suffix[x + 1]

    ans = 0
    for l in range(1, M + 1):
        r0 = suffix[l]
        if r0 == INF:
            r0 = M + 1
        if r0 > l:
            ans += r0 - l   # max(0, r0 - l)

    print(ans)


