def solve() -> None:
    H, W, K = map(int, sys.stdin.readline().split())
    grid = [sys.stdin.readline().strip() for _ in range(H)]

    idx = [[-1] * W for _ in range(H)]
    cells = []                     # list of (i,j) for each empty cell
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.':
                idx[i][j] = len(cells)
                cells.append((i, j))

    N = len(cells)
    adj = [[] for _ in range(N)]
    dirs = [(1,0), (-1,0), (0,1), (0,-1)]
    for k, (i, j) in enumerate(cells):
        for di, dj in dirs:
            ni, nj = i + di, j + dj
            if 0 <= ni < H and 0 <= nj < W and grid[ni][nj] == '.':
                adj[k].append(idx[ni][nj])

    # depth‑first search
    from functools import lru_cache

    @lru_cache(maxsize=None)
    def dfs(v: int, depth: int, mask: int) -> int:
        if depth == K:
            return 1
        total = 0
        for to in adj[v]:
            if not (mask >> to) & 1:
                total += dfs(to, depth + 1, mask | (1 << to))
        return total

    ans = 0
    for s in range(N):
        ans += dfs(s, 0, 1 << s)

    print(ans)


