def solve() -> None:
    it = iter(sys.stdin.read().split())
    n = int(next(it))
    adj = [[] for _ in range(n)]
    edges = []
    for _ in range(n - 1):
        u = int(next(it)) - 1
        v = int(next(it)) - 1
        adj[u].append(v)
        adj[v].append(u)
        edges.append((u, v))

    deg = [len(adj[i]) for i in range(n)]

    # leafCnt for vertices of degree 3
    leaf_cnt = [0] * n
    for v in range(n):
        if deg[v] == 3:
            cnt = 0
            for nb in adj[v]:
                if deg[nb] == 2:
                    cnt += 1
            leaf_cnt[v] = cnt

    # DSU for vertices with degree 3, joining only edges (3,3)
    parent = list(range(n))
    size = [1] * n

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    def union(a, b):
        ra, rb = find(a), find(b)
        if ra == rb:
            return
        if size[ra] < size[rb]:
            ra, rb = rb, ra
        parent[rb] = ra
        size[ra] += size[rb]

    for u, v in edges:
        if deg[u] == 3 and deg[v] == 3:
            union(u, v)

    # sum leaf_cnt inside each component of degree‑3 vertices
    comp_sum = dict()
    for v in range(n):
        if deg[v] == 3:
            r = find(v)
            comp_sum[r] = comp_sum.get(r, 0) + leaf_cnt[v]

    # total pairs from components
    ans = 0
    for total in comp_sum.values():
        if total >= 2:
            ans += total * (total - 1) // 2

    # subtract pairs that are already adjacent
    for u, v in edges:
        if deg[u] == 2 and deg[v] == 2:
            # does u have a neighbour of degree 3 ?
            ok_u = any(deg[w] == 3 for w in adj[u])
            ok_v = any(deg[w] == 3 for w in adj[v])
            if ok_u and ok_v:
                ans -= 1

    print(ans)


