import sys, random
sys.setrecursionlimit(1 << 25)

# ---------- treap node ----------
class Node:
    __slots__ = ('l', 'r', 'col', 'prio', 'left', 'right')
    def __init__(self, l, r, col):
        self.l = l
        self.r = r
        self.col = col
        self.prio = random.getrandbits(30)
        self.left = None
        self.right = None

# ---------- treap basic operations ----------
def merge(a, b):
    if not a or not b:
        return a or b
    if a.prio > b.prio:
        a.right = merge(a.right, b)
        return a
    else:
        b.left = merge(a, b.left)
        return b

def split(root, key):
    """ keys < key go to left part """
    if not root:
        return (None, None)
    if key <= root.l:
        left, right = split(root.left, key)
        root.left = right
        return (left, root)
    else:
        left, right = split(root.right, key)
        root.right = left
        return (root, right)

def insert(root, node):
    if not root:
        return node
    if node.prio > root.prio:
        left, right = split(root, node.l)
        node.left = left
        node.right = right
        return node
    elif node.l < root.l:
        root.left = insert(root.left, node)
    else:
        root.right = insert(root.right, node)
    return root

def erase(root, key):
    if not root:
        return None
    if key < root.l:
        root.left = erase(root.left, key)
        return root
    elif key > root.l:
        root.right = erase(root.right, key)
        return root
    else:               # found
        return merge(root.left, root.right)

def find(root, x):
    """ return node whose interval contains x """
    while root:
        if x < root.l:
            root = root.left
        elif x > root.r:
            root = root.right
        else:
            return root
    return None

def predecessor(root, key):
    """ greatest node with L < key """
    ans = None
    while root:
        if root.l < key:
            ans = root
            root = root.right
        else:
            root = root.left
    return ans

def successor(root, key):
    """ smallest node with L > key """
    ans = None
    while root:
        if root.l > key:
            ans = root
            root = root.left
        else:
            root = root.right
    return ans

# ---------- main solving ----------
def solve() -> None:
    data = list(map(int, sys.stdin.buffer.read().split()))
    it = iter(data)
    N = next(it)
    Q = next(it)

    cnt = [0] * (N + 1)
    for i in range(1, N + 1):
        cnt[i] = 1

    root = None
    # build initial treap: N singletons
    for i in range(1, N + 1):
        root = insert(root, Node(i, i, i))

    out_lines = []
    for _ in range(Q):
        typ = next(it)
        if typ == 2:
            c = next(it)
            out_lines.append(str(cnt[c]))
        else:               # typ == 1
            x = next(it)
            c = next(it)

            node = find(root, x)
            L, R, old = node.l, node.r, node.col
            if old == c:
                continue

            length = R - L + 1
            cnt[old] -= length
            cnt[c]   += length

            root = erase(root, L)

            # merge with left neighbour if possible
            left = predecessor(root, L)
            if left and left.col == c and left.r == L - 1:
                L = left.l
                root = erase(root, left.l)

            # merge with right neighbour if possible
            right = successor(root, R)
            if right and right.col == c and right.l == R + 1:
                R = right.r
                root = erase(root, right.l)

            root = insert(root, Node(L, R, c))

    sys.stdout.write("\n".join(out_lines))

