def solve() -> None:
    data = sys.stdin.read().split()
    if not data:
        return
    it = iter(data)
    S = next(it).strip()
    n = len(S)
    Q = int(next(it))
    ks = [int(next(it)) for _ in range(Q)]

    # pre‑compute flipped version of each character to avoid repeated work
    flip = {}
    for ch in set(S):
        if ch.islower():
            flip[ch] = ch.upper()
        else:
            flip[ch] = ch.lower()

    out = []
    for K in ks:
        k0 = K - 1
        b = k0 // n
        offset = k0 % n
        base = S[offset]
        if b.bit_count() & 1:          # odd popcount -> flipped block
            out.append(flip[base])
        else:
            out.append(base)

    sys.stdout.write(' '.join(out))

