def solve() -> None:
    data = sys.stdin.read().splitlines()
    if not data:
        return
    N = int(data[0].strip())
    S = data[1].strip()
    # safety: ensure length matches N
    # (the problem guarantees it)
    n = N

    # ones[i] = length of consecutive '1's ending at i
    ones = [0] * n
    for i in range(n):
        if S[i] == '1':
            ones[i] = (ones[i-1] if i > 0 else 0) + 1
        else:
            ones[i] = 0

    # twos[i] = length of consecutive '2's starting at i
    twos = [0] * n
    for i in range(n-1, -1, -1):
        if S[i] == '2':
            twos[i] = (twos[i+1] if i+1 < n else 0) + 1
        else:
            twos[i] = 0

    ans = 0
    for i, ch in enumerate(S):
        if ch != '/':
            continue
        L = ones[i-1] if i > 0 else 0
        R = twos[i+1] if i+1 < n else 0
        cur = 2 * min(L, R) + 1
        if cur > ans:
            ans = cur

    print(ans)

