def solve() -> None:
    it = iter(sys.stdin.read().splitlines())
    H, W, D = map(int, next(it).split())
    grid = [list(next(it).rstrip()) for _ in range(H)]

    visited = [[False] * W for _ in range(H)]
    q = deque()
    for i in range(H):
        for j in range(W):
            if grid[i][j] == 'H':
                visited[i][j] = True
                q.append((i, j, 0))

    ans = 0
    # directions: up, down, left, right
    dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    while q:
        r, c, dist = q.popleft()
        ans += 1
        if dist == D:
            continue
        nd = dist + 1
        for dr, dc in dirs:
            nr, nc = r + dr, c + dc
            if 0 <= nr < H and 0 <= nc < W:
                if not visited[nr][nc] and grid[nr][nc] != '#':
                    visited[nr][nc] = True
                    q.append((nr, nc, nd))

    print(ans)

