import sys

def solve() -> None:
    it = iter(sys.stdin.read().splitlines())
    H, W, D = map(int, next(it).split())
    grid = [list(next(it).strip()) for _ in range(H)]

    floors = []                     # list of (r, c)
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.':
                floors.append((i, j))

    N = len(floors)
    masks = [0] * N                 # int bitmask for each floor cell

    # pre‑compute masks
    for i, (ri, ci) in enumerate(floors):
        m = 0
        for j, (rj, cj) in enumerate(floors):
            if abs(ri - rj) + abs(ci - cj) <= D:
                m |= 1 << j
        masks[i] = m

    best = 0
    for i in range(N):
        mi = masks[i]
        for j in range(i + 1, N):
            cnt = (mi | masks[j]).bit_count()
            if cnt > best:
                best = cnt

    print(best)


