import sys

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    H = [int(next(it)) for _ in range(N)]

    # group positions (1‑based) by height
    pos_by_height = {}
    for idx, h in enumerate(H, start=1):
        pos_by_height.setdefault(h, []).append(idx)

    answer = 1  # at least one building can always be chosen

    for positions in pos_by_height.values():
        k = len(positions)
        if k <= answer:          # cannot improve the current answer
            continue
        # dp[i] : dict {diff : length ending at positions[i]}
        dp = [dict() for _ in range(k)]
        for i in range(k):
            pi = positions[i]
            dpi = dp[i]
            for j in range(i):
                d = pi - positions[j]          # positive
                prev_len = dp[j].get(d, 1)     # length ending at j, or just j
                cur_len = prev_len + 1
                # keep the best length for this diff at i
                if cur_len > dpi.get(d, 0):
                    dpi[d] = cur_len
                    if cur_len > answer:
                        answer = cur_len

    print(answer)


