def solve() -> None:
    it = iter(sys.stdin.read().strip().split())
    N = int(next(it))
    blocked = [[False] * (N + 1) for _ in range(N + 1)]
    for _ in range(N):
        x = int(next(it))
        y = int(next(it))
        blocked[x][y] = True

    # dp[x][y] : number of admissible paths from (0,N) to (x,y)
    dp = [[0] * (N + 1) for _ in range(N + 1)]
    dp[0][N] = 1  # start cell is never blocked

    for x in range(N + 1):
        for y in range(N, -1, -1):
            if blocked[x][y]:
                continue
            cur = dp[x][y]
            if cur == 0:
                continue
            # east
            if x + 1 <= N and not blocked[x + 1][y]:
                dp[x + 1][y] = (dp[x + 1][y] + cur) % MOD
            # south
            if y - 1 >= 0 and not blocked[x][y - 1]:
                dp[x][y - 1] = (dp[x][y - 1] + cur) % MOD

    print(dp[N][0] % MOD)


