import sys

MOD = 998244353

def modinv(x):
    return pow(x, MOD - 2, MOD)

def prepare_fact(n):
    fact = [1] * (n + 1)
    inv_fact = [1] * (n + 1)
    for i in range(1, n + 1):
        fact[i] = fact[i - 1] * i % MOD
    inv_fact[n] = modinv(fact[n])
    for i in range(n, 0, -1):
        inv_fact[i - 1] = inv_fact[i] * i % MOD
    return fact, inv_fact

def comb(n, k, fact, inv_fact):
    if k < 0 or k > n:
        return 0
    return fact[n] * inv_fact[k] % MOD * inv_fact[n - k] % MOD

def f(x, y, N, fact, inv_fact):
    """ Σ_{k=0}^{min(x,y)} (-1)^k C(x,k) C(y,k) k! (N-k)! """
    limit = min(x, y)
    res = 0
    sign = 1
    for k in range(limit + 1):
        term = comb(x, k, fact, inv_fact) * comb(y, k, fact, inv_fact) % MOD
        term = term * fact[k] % MOD
        term = term * fact[N - k] % MOD
        if sign == 1:
            res += term
        else:
            res -= term
        sign ^= 1  # flip sign
    return res % MOD

def solve() -> None:
    it = iter(sys.stdin.read().split())
    N = int(next(it))
    A = [int(next(it)) for _ in range(N)]
    B = [int(next(it)) for _ in range(N)]

    # sign[i] : 0 = odd a_i (p2[i] < partner), 1 = even a_i
    sign = [0] * N
    L = R = 0
    for i, a in enumerate(A):
        sign[i] = a & 1          # 1 if odd -> 1, but we need 0 for odd
        # we want 0 for odd, 1 for even
        sign[i] ^= 1
        if sign[i] == 0:
            L += 1
        else:
            R += 1

    cnt0 = cnt1 = 0
    U = 0
    for b in B:
        if b == -1:
            U += 1
        elif b & 1:
            cnt0 += 1          # known odd
        else:
            cnt1 += 1          # known even

    fact, inv_fact = prepare_fact(N)

    ans = f(L, cnt0, N, fact, inv_fact)
    ans = ans * f(R, cnt1, N, fact, inv_fact) % MOD
    ans = ans * f(U, U, N, fact, inv_fact) % MOD
    print(ans)

if __name__ == "__main__":
    solve()

