class Solution:
    def countWinningSequences(self, s: str) -> int:
        n = len(s)
        # encode moves: 0 = F, 1 = W, 2 = E
        enc = {'F': 0, 'W': 1, 'E': 2}
        a = [enc[ch] for ch in s]

        # beats[x] = creature that x defeats
        beats = [2, 0, 1]          # F beats E, W beats F, E beats W

        offset = n                 # shift for negative indices
        size = 2 * n + 1           # possible diff values: -n .. n

        # dp[last][diff+offset]  for the already processed prefix
        dp = [[0] * size for _ in range(3)]

        # ----- initialise first round -----
        for cur in range(3):
            if cur == a[0]:
                delta = 0
            elif beats[cur] == a[0]:
                delta = 1
            else:
                delta = -1
            dp[cur][delta + offset] = 1

        # ----- process remaining rounds -----
        for i in range(1, n):
            ndp = [[0] * size for _ in range(3)]
            alice_move = a[i]

            for last in range(3):
                row = dp[last]
                for idx, cnt in enumerate(row):
                    if cnt == 0:
                        continue
                    diff = idx - offset

                    # try every possible current move different from 'last'
                    for cur in range(3):
                        if cur == last:
                            continue
                        # round contribution
                        if cur == alice_move:
                            delta = 0
                        elif beats[cur] == alice_move:
                            delta = 1
                        else:
                            delta = -1

                        ndiff = diff + delta
                        ndp[cur][ndiff + offset] = (ndp[cur][ndiff + offset] + cnt) % MOD

            dp = ndp

        # ----- sum all winning final states -----
        ans = 0
        for last in range(3):
            for idx in range(offset + 1, size):   # diff > 0
                ans = (ans + dp[last][idx]) % MOD

        return ans

class Solution:
    def numberOfSubstrings(self, s: str, k: int) -> int:
        n = len(s)
        # k == 1 → every substring is valid
        if k == 1:
            return n * (n + 1) // 2

        ans = 0
        for i in range(n):
            cnt = [0] * 26          # frequency of each letter in current window
            satisfied = False
            for j in range(i, n):
                idx = ord(s[j]) - ord('a')
                cnt[idx] += 1
                if cnt[idx] == k:   # first time this character reaches k
                    satisfied = True
                if satisfied:
                    # all substrings s[i..j], s[i..j+1], ..., s[i..n-1] are valid
                    ans += n - j
                    break            # move to next starting position
        return ans

