class Solution:
    def minOperations(self, nums: List[int]) -> int:
        if not nums:
            return 0

        max_val = max(nums)
        # ---------- smallest prime factor sieve ----------
        spf = [0] * (max_val + 1)
        spf[0] = 0
        if max_val >= 1:
            spf[1] = 1
        for i in range(2, max_val + 1):
            if spf[i] == 0:                 # i is prime
                spf[i] = i
                if i * i <= max_val:
                    for j in range(i * i, max_val + 1, i):
                        if spf[j] == 0:
                            spf[j] = i

        INF = 10 ** 9

        # ---------- DP initialisation ----------
        a0 = nums[0]
        val0 = a0
        dp0 = 0                     # keep original
        # can we reduce the first element ?
        if a0 > 1 and spf[a0] != a0:        # composite
            val1 = spf[a0]          # smallest prime factor
            dp1 = 1                 # one operation
        else:
            val1 = INF
            dp1 = INF

        # ---------- DP over the rest ----------
        for idx in range(1, len(nums)):
            a = nums[idx]
            cur0 = a
            # reduced value (if composite)
            if a > 1 and spf[a] != a:
                cur1 = spf[a]
                cost1 = 1
            else:
                cur1 = INF
                cost1 = INF

            ndp0 = INF
            ndp1 = INF

            # transition from previous state 0 (keep previous)
            if dp0 < INF:
                if val0 <= cur0:
                    ndp0 = min(ndp0, dp0)
                if cur1 < INF and val0 <= cur1:
                    ndp1 = min(ndp1, dp0 + cost1)

            # transition from previous state 1 (reduced previous)
            if dp1 < INF:
                if val1 <= cur0:
                    ndp0 = min(ndp0, dp1)
                if cur1 < INF and val1 <= cur1:
                    ndp1 = min(ndp1, dp1 + cost1)

            # move to next position
            val0, val1 = cur0, cur1
            dp0, dp1 = ndp0, ndp1

        ans = min(dp0, dp1)
        return -1 if ans >= INF else ans

