class Solution:
    def hasIncreasingSubarrays(self, nums: List[int], k: int) -> bool:
        n = len(nums)
        # inc[i] = length of longest strictly increasing run starting at i
        inc = [1] * n
        for i in range(n - 2, -1, -1):
            if nums[i] < nums[i + 1]:
                inc[i] = inc[i + 1] + 1
            else:
                inc[i] = 1

        # check every possible first start index a
        for a in range(0, n - 2 * k + 1):
            if inc[a] >= k and inc[a + k] >= k:
                return True
        return False

