class Solution:
    def minimumSumSubarray(self, nums: List[int], l: int, r: int) -> int:
        n = len(nums)
        # prefix sums: pref[i] = sum of first i elements (0 <= i <= n)
        pref = [0] * (n + 1)
        for i in range(n):
            pref[i + 1] = pref[i] + nums[i]

        INF = float('inf')
        best = INF

        for i in range(n):
            for j in range(i, n):
                length = j - i + 1
                if l <= length <= r:
                    s = pref[j + 1] - pref[i]   # Lemma 1
                    if s > 0:
                        if s < best:
                            best = s

        return -1 if best == INF else best

