class Solution:
    def minArraySum(self, nums: List[int], k: int, op1: int, op2: int) -> int:
        n = len(nums)
        INF = 10 ** 15

        # dp[c1][c2] – current layer (processed some prefix)
        dp = [[INF] * (op2 + 1) for _ in range(op1 + 1)]
        dp[0][0] = 0

        for a in nums:
            ndp = [[INF] * (op2 + 1) for _ in range(op1 + 1)]
            for c1 in range(op1 + 1):
                for c2 in range(op2 + 1):
                    cur = dp[c1][c2]
                    if cur == INF:
                        continue

                    # 1) do nothing
                    if cur + a < ndp[c1][c2]:
                        ndp[c1][c2] = cur + a

                    # 2) operation 1 only
                    if c1 < op1:
                        val1 = (a + 1) // 2          # ceil(a/2)
                        if cur + val1 < ndp[c1 + 1][c2]:
                            ndp[c1 + 1][c2] = cur + val1

                    # 3) operation 2 only
                    if c2 < op2 and a >= k:
                        val2 = a - k
                        if cur + val2 < ndp[c1][c2 + 1]:
                            ndp[c1][c2 + 1] = cur + val2

                    # 4) both operations
                    if c1 < op1 and c2 < op2:
                        best = INF

                        # order: op1 then op2
                        after_op1 = (a + 1) // 2
                        if after_op1 >= k:
                            best = min(best, after_op1 - k)

                        # order: op2 then op1
                        if a >= k:
                            after_op2 = a - k
                            best = min(best, (after_op2 + 1) // 2)

                        if best != INF:
                            if cur + best < ndp[c1 + 1][c2 + 1]:
                                ndp[c1 + 1][c2 + 1] = cur + best

            dp = ndp

        # minimal value among all states that used at most op1/op2 operations
        ans = INF
        for c1 in range(op1 + 1):
            for c2 in range(op2 + 1):
                ans = min(ans, dp[c1][c2])
        return ans

