class Solution:
    def maxScore(self, n: int, k: int,
                 stayScore: List[List[int]],
                 travelScore: List[List[int]]) -> int:
        INF_NEG = -10**9          # sufficiently small

        # dp_prev[c] = best score after previous day, ending in city c
        dp_prev = [0] * n         # before day 0 we may start anywhere with 0 points

        for day in range(k):
            dp_cur = [INF_NEG] * n
            for dest in range(n):
                # option 1: stay in the same city
                stay = dp_prev[dest] + stayScore[day][dest]
                best = stay

                # option 2: come from any other city (including same, travelScore[i][i]=0)
                # we simply scan all possible previous cities
                tr_max = INF_NEG
                for prev in range(n):
                    cand = dp_prev[prev] + travelScore[prev][dest]
                    if cand > tr_max:
                        tr_max = cand
                if tr_max > best:
                    best = tr_max

                dp_cur[dest] = best
            dp_prev = dp_cur

        return max(dp_prev)

class Solution:
    def smallestNumber(self, n: int, t: int) -> int:
        """
        Returns the smallest integer m >= n such that the product of its decimal
        digits is divisible by t.
        """
        def digit_product(x: int) -> int:
            """Compute product of decimal digits of x."""
            prod = 1
            while x > 0:
                prod *= x % 10
                x //= 10
            return prod

        x = n
        while True:
            if digit_product(x) % t == 0:
                return x
            x += 1

