class Solution:
    def maxRectangleArea(self, points: List[List[int]]) -> int:
        # store points as a set of tuples for O(1) lookup
        point_set = { (x, y) for x, y in points }
        n = len(points)
        max_area = -1

        # iterate over all unordered pairs of distinct points
        for i in range(n):
            x1, y1 = points[i]
            for j in range(i + 1, n):
                x2, y2 = points[j]

                # need two different x and two different y to form a rectangle
                if x1 == x2 or y1 == y2:
                    continue

                # the four corners that this rectangle would have
                corners = {
                    (x1, y1), (x1, y2),
                    (x2, y1), (x2, y2)
                }

                # all four corners must be present in the input
                if not corners.issubset(point_set):
                    continue

                min_x, max_x = (x1, x2) if x1 < x2 else (x2, x1)
                min_y, max_y = (y1, y2) if y1 < y2 else (y2, y1)

                # verify that no other point lies inside or on the border
                ok = True
                for (px, py) in point_set:
                    if (px, py) in corners:
                        continue
                    if min_x <= px <= max_x and min_y <= py <= max_y:
                        ok = False
                        break

                if ok:
                    area = (max_x - min_x) * (max_y - min_y)
                    if area > max_area:
                        max_area = area

        return max_area

