class Solution:
    def minOperations(self, nums: List[int], k: int) -> int:
        # if any element is smaller than k, impossible
        for x in nums:
            if x < k:
                return -1

        # distinct values strictly larger than k
        larger = set()
        for x in nums:
            if x > k:
                larger.add(x)

        # each distinct larger value needs one operation
        return len(larger)

