class Solution:
    def findMinimumTime(self, strength: List[int], K: int) -> int:
        n = len(strength)
        full = (1 << n) - 1
        INF = 10 ** 18
        dp = [INF] * (1 << n)
        dp[0] = 0

        for mask in range(1 << n):
            b = mask.bit_count()               # how many locks already broken
            X = 1 + b * K                       # current factor
            cur = dp[mask]
            if cur == INF:
                continue
            for i in range(n):
                if mask & (1 << i):
                    continue                  # already broken
                nxt = mask | (1 << i)
                # minutes needed for this lock
                cost = (strength[i] + X - 1) // X
                if cur + cost < dp[nxt]:
                    dp[nxt] = cur + cost

        return dp[full]

