class DSU:
    __slots__ = ("parent", "size")
    def __init__(self, n: int):
        self.parent = list(range(n))
        self.size = [1] * n

    def find(self, x: int) -> int:
        # path compression
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]
            x = self.parent[x]
        return x

    def union(self, a: int, b: int) -> None:
        ra, rb = self.find(a), self.find(b)
        if ra == rb:
            return
        # union by size
        if self.size[ra] < self.size[rb]:
            ra, rb = rb, ra
        self.parent[rb] = ra
        self.size[ra] += self.size[rb]


class Solution:
    def countComponents(self, nums: List[int], threshold: int) -> int:
        n = len(nums)
        dsu = DSU(n)

        # map value -> its index in nums
        val_to_idx = {v: i for i, v in enumerate(nums)}

        # first[m] = index of the first number that divides m (m ≤ threshold)
        first = [-1] * (threshold + 1)

        for v in nums:
            if v > threshold:
                continue          # isolated, never participates in unions
            idx = val_to_idx[v]
            step = v
            # walk through all multiples of v not larger than threshold
            for mult in range(step, threshold + 1, step):
                if first[mult] == -1:
                    first[mult] = idx
                else:
                    dsu.union(idx, first[mult])

        # count distinct roots
        roots = set()
        for i in range(n):
            roots.add(dsu.find(i))
        return len(roots)

