from collections import defaultdict, deque

class Solution:
    def maxAmount(self,
                  initialCurrency: str,
                  pairs1: List[List[str]], rates1: List[float],
                  pairs2: List[List[str]], rates2: List[float]) -> float:
        # ---------- helper to build graph ----------
        def build_graph(pairs: List[List[str]], rates: List[float]) -> Dict[str, List[tuple]]:
            g = defaultdict(list)
            for (a, b), r in zip(pairs, rates):
                g[a].append((b, r))          # a -> b
                g[b].append((a, 1.0 / r))    # b -> a (inverse)
            return g

        # ---------- BFS that computes value[vertex] ----------
        def bfs_values(graph: Dict[str, List[tuple]], root: str) -> Dict[str, float]:
            values = {root: 1.0}
            q = deque([root])
            while q:
                cur = q.popleft()
                cur_val = values[cur]
                for nxt, rate in graph.get(cur, []):
                    if nxt not in values:
                        values[nxt] = cur_val * rate
                        q.append(nxt)
            return values

        # Build both day graphs
        g1 = build_graph(pairs1, rates1)
        g2 = build_graph(pairs2, rates2)

        # Values for day 1 (starting from initialCurrency)
        value1 = bfs_values(g1, initialCurrency)

        # Values for day 2.
        # If the initial currency does not appear in day‑2 graph we still need
        # value2[initial] = 1 so that staying idle is considered.
        if initialCurrency in g2:
            value2 = bfs_values(g2, initialCurrency)
        else:
            value2 = {initialCurrency: 1.0}

        # Compute the best achievable amount
        best = 1.0   # doing nothing
        for cur in value1:
            if cur in value2:
                amount = value1[cur] / value2[cur]   # value1 * (1/value2)
                if amount > best:
                    best = amount
        return best

class Solution:
    def answerString(self, word: str, numFriends: int) -> str:
        n = len(word)
        max_len = n - numFriends + 1          # maximal allowed length of a piece
        # the largest character that can start the answer
        max_char = max(word)

        best = ""                             # current best candidate
        # iterate over all positions where the character equals max_char
        for i, ch in enumerate(word):
            if ch != max_char:
                continue
            # substring of length at most max_len starting at i
            cand = word[i:i + max_len]
            if cand > best:
                best = cand
        return best

MOD = 10**9 + 7

class Solution:
    def countGoodArrays(self, n: int, m: int, k: int) -> int:
        # r = n - k runs, need C(n-1, k) * m * (m-1)^{n-k-1}
        if k > n - 1:
            return 0

        # pre‑compute factorials up to n
        max_n = n
        fact = [1] * (max_n + 1)
        for i in range(1, max_n + 1):
            fact[i] = fact[i - 1] * i % MOD

        inv_fact = [1] * (max_n + 1)
        inv_fact[max_n] = pow(fact[max_n], MOD - 2, MOD)   # Fermat
        for i in range(max_n, 0, -1):
            inv_fact[i - 1] = inv_fact[i] * i % MOD

        # binomial C(n-1, k)
        comb = fact[n - 1] * inv_fact[k] % MOD * inv_fact[n - 1 - k] % MOD

        # (m-1)^{n-k-1}
        exp = n - k - 1
        pow_part = pow(m - 1, exp, MOD) if exp >= 0 else 1  # exp is always >=0

        ans = comb * m % MOD * pow_part % MOD
        return ans

