MOD = 10**9 + 7
MAX_XOR = 16          # values are 0..15

class Solution:
    def countPathsWithXorValue(self, grid: List[List[int]], k: int) -> int:
        m, n = len(grid), len(grid[0])

        # dp[i][j][x] – number of ways to reach (i,j) with XOR == x
        dp = [[[0] * MAX_XOR for _ in range(n)] for _ in range(m)]

        start_val = grid[0][0]
        dp[0][0][start_val] = 1

        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                cur = grid[i][j]
                cur_dp = dp[i][j]

                # from top
                if i > 0:
                    top = dp[i-1][j]
                    for x in range(MAX_XOR):
                        cnt = top[x]
                        if cnt:
                            cur_dp[x ^ cur] = (cur_dp[x ^ cur] + cnt) % MOD

                # from left
                if j > 0:
                    left = dp[i][j-1]
                    for x in range(MAX_XOR):
                        cnt = left[x]
                        if cnt:
                            cur_dp[x ^ cur] = (cur_dp[x ^ cur] + cnt) % MOD

        return dp[m-1][n-1][k] % MOD
